VALUES
  ('aboriginal-c5fb3965-moex-00028', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '率先承認原住民族語言是國家語言之法律，請問是下列那個法律？', '["國家語言發展法", "原住民族教育法", "原住民族基本法", "原住民族語言發展法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00029', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '有關原住民族教育法之規範，下列描述何者錯誤？', '["原住民幼兒申請就讀公立幼兒園、非營利幼兒園、社區或部落互助教保服務中心時，有優先權", "教育主管機關為發展原住民族教育，得指定所屬公立高級中等以下學校，或由學校提出申請，辦理 部分班級實驗教育", "大專校院之原住民學生達一定人數或比率者，中央教育主管機關應鼓勵設置原住民族教育資源 中心，辦理原住民族教育課程、教材與教學方法之研發及推廣，並指定專責人員，以輔導其生活及 學業", "各級教育主管機關為發展原住民族教育，得指定所屬公立高級中等以下學校，或由學校提出申請， 準用學校型態實驗教育實施條例之規定，辦理學校型態實驗教育"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00030', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '針對原住民族基本法第2條規定所稱「部落」，下列描述何者錯誤？', '["部落為公法人", "部落應有一定區域", "部落均坐落於原住民族地區", "部落是原住民所組成的團體"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00031', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民族土地或部落範圍土地劃設辦法規定，原住民族傳統領域土地之定義為何？', '["具原住民傳統居住，具有原住民族歷史淵源及文化特色之地區", "原住民族傳統祭儀、祖靈聖地、部落及其獵區與墾耕或其他依原住民族文化、傳統習慣等特徵可得 確定其範圍之公有土地", "原住民於中華民國77年2月1日前即使用其祖先遺留且目前仍繼續使用之公有土地", "原住民族部落之傳統生活空間，包含部落、農耕地、獵場等區域"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00032', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據土地徵收條例及其施行細則規定，辦理區段徵收涉及原住民族土地時，其區段徵收書內應檢附何 種證明文件？', '["當地鄉（鎮、市、區）公所開立之諮商取得原住民族部落同意證明書", "原住民族委員會之書面同意文件", "該筆土地所有權人之同意文件", "部落會議議決同意之證明文件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00033', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民族基本法明文規定政府應辦理之原住民族住宅政策，下列何者不包含在內？', '["輔導原住民建購住宅", "輔導原住民租用住宅", "輔導原住民修繕住宅", "推動部落更新計畫方案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00034', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民族基本法明文規定政府應辦理之原住民族地區建設政策，下列何者正確？', '["政府應設置原住民族地區建設基金", "政府應強化軌道建設、水環境建設、綠能建設、數位建設等建設措施", "政府應規劃辦理花東地區永續發展策略計畫", "政府應寬列預算並督促公用事業機構，積極改善原住民族地區之交通運輸、郵政、電信、水利、觀 光及其他公共工程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00035', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民申請無償取得原住民保留地所有權，其面積限制之規定，下列描述何者正確？', '["依區域計畫法編定為農牧用地、養殖用地或依都市計畫法劃定為農業區、保護區，並供農作、養殖 或畜牧使用之土地，每人一點五公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人二公頃", "基於地形限制，得為百分之十以內之增加", "依法得為建築使用之土地，每戶零點二公頃"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00036', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '針對非原住民承租公有原住民保留地之有關規定，下列描述何者正確？', '["依民法第449條規定，每一租期最長20年", "承租人違反計畫使用者，應依法規定裁罰，不得逕予中止租約，以保障人民財產權", "因興辦宗教建築設施（如教會、教堂）而申請使用者，得無償使用原住民保留地內依法得為建築使 用之土地", "非原住民在轄有原住民保留地之鄉（鎮、市、區）內設有戶籍者，即可租用該鄉（鎮、市、區）內 依法得為建築使用之原住民保留地作為自住房屋基地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00037', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民族地區內某 A 鄉公所辦理原住民保留地分配作業，現有下列四個原住民提出申請，請問依原 住民保留地開發管理辦法規定，誰應優先獲得分配？', '["某甲，現職公務人員，原受配原住民保留地面積未達最高限額，且與該土地具有傳統淵源關係", "某乙，低收入戶，名下沒有財產，也未受配原住民保留地", "某丙，名下原住民保留地被政府徵收辦理部落內公共工程，以致面積減少", "某丁，本部落傳統領袖，依傳統規範擁有對部落土地之管領權力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
